from sqlalchemy.orm import Mapped, mapped_columnfrom database.entity.BaseModel import BaseModelfrom typing import Optionalfrom sqlalchemy import TIMESTAMP,BIGINT,TEXT,VARCHAR,BOOLEAN,UUIDimport uuid,datetimefrom sqlalchemy.dialects.postgresql import INETclass PlatformUserAuthLogModel(BaseModel):    __tablename__ = 'platform_user_auth_log'    id: Mapped[int] = mapped_column(BIGINT, autoincrement=True, primary_key=True)    user_id: Mapped[Optional[uuid.UUID]] = mapped_column(UUID)    action: Mapped[Optional[str]] = mapped_column(VARCHAR(30), comment="""register/login/logout/verify/reset_pwd""")    ip_addr: Mapped[Optional[str]] = mapped_column(INET)    user_agent: Mapped[Optional[str]] = mapped_column(TEXT)    success: Mapped[Optional[bool]] = mapped_column(BOOLEAN)    create_at: Mapped[datetime.datetime] = mapped_column(TIMESTAMP)